module traffic_light
(
    input rst_n,
    input clk,
    input pass_request,
    output [7:0] clock,
    output reg red
);
// TODO: Please fill in your logic design here
// Declare any additional reg or wire variables as needed
// Parameters and logic description
    parameter idle = 2'b00;
    parameter s1_red = 2'b01;
    parameter s2_yellow = 2'b10;
    parameter s3_green = 2'b11;
    reg [1:0] state, next_state;
    reg [1:0] p_red, p_yellow, p_green;
    reg [7:0] cnt;
// always block for state transition
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state <= idle;
        end
        else begin
            case (state)
                idle: begin
                    state <= s1_red;
                end
                s1_red: begin
                    if (cnt == 3) begin
                        state <= s3_green;
                    end
                    else begin
                        state <= s1_red;
                    end
                end
                s2_yellow: begin
                    if (cnt == 3) begin
                        state <= s1_red;
                    end
                    else begin
                        state <= s2_yellow;
                    end
                end
                s3_green: begin
                    if (cnt == 3) begin
                        state <= s2_yellow;
                    end
                    else begin
                        state <= s3_green;
                    end
                end
            endcase
        end
    end
// always block for counter
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 10;
        end
        else begin
            if (pass_request && green) begin
                cnt <= 10;
            end
            else if (!green && p_green) begin
                cnt <= 60;
            end
            else if (!yellow && p_yellow) begin
                cnt <= 5;
            end
            else if (!red && p_red) begin
                cnt <= 10;
            end
            else begin
                cnt <= cnt - 1;
            end
        end
    end
// assign statement for output signals
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            red <= 0;
            yellow <= 0;
            green <= 0;
        end
        else begin
            red <= p_red;
            yellow <= p_yellow;
            green <= p_green;
        end
    end
endmodule
